const bundle = (effects: EffectBundle["effects"]): EffectBundle =>
  makeEffectBundleFixture(
    effects,
    validQuaffTriggerFixture,
    validSelfTargetingFixture
  );

const context = (
  seed: string,
  overrides: Partial<EffectExecutionContext> = {}
): EffectExecutionContext => ({
  sourceId: "player",
  targetId: "player",
  origin: null,
  rng: createRng(seed),
  ...overrides
});

const withPlayerHp = (
  state: GameState,
  current: number,
  max: number
): GameState => ({
  ...state,
  player: {
    ...state.player,
    hp: {
      current,
      max
    }
  }
});

const withPlayerFullness = (
  state: GameState,
  current: number,
  max: number
): GameState => ({
  ...state,
  player: {
    ...state.player,
    fullness: {
      current,
      max
    }
  }
});

const withEnemy = (
  state: GameState,
  enemyEntity: EnemyEntityInstance
): GameState => ({
  ...state,
  entities: {
    ...state.entities,
    [enemyEntity.id]: enemyEntity
  }
});

const enemy = (
  id: EntityId,
  hp: number,
  position: Position = { x: 1, y: 0 },
  overrides: Partial<EnemyDefinition["stats"]> = {}
): EnemyEntityInstance => {
  const stats = {
    ...validEnemyDefinitionFixture.stats,
    hp,
    ...overrides
  };

  return {
    id,
    kind: "enemy",
    definition: {
      ...validEnemyDefinitionFixture,
      stats
    } as unknown as EnemyEntityInstance["definition"],
    position,
    currentHP: hp,
    statuses: [],
    behaviorRuntime: {}
  };
};

const withInventory = (
  state: GameState,
  stacks: readonly PlayerItemStack[]
): GameState => ({
  ...state,
  player: {
    ...state.player,
    inventory: [
      ...stacks,
      ...Array.from(
        { length: state.player.inventory.length - stacks.length },
        () => null
      )
    ]
  }
});

const withEquipment = (
  state: GameState,
  equipment: Partial<GameState["player"]["equipment"]>
): GameState => ({
  ...state,
  player: {
    ...state.player,
    equipment: {
      ...state.player.equipment,
      ...equipment
    }
  }
});

const carried = (
  itemInstanceId: string,
  definition: ItemDefinition,
  identified: boolean
): PlayerItemStack => ({
  itemInstanceId,
  definition,
  quantity: 1,
  identified
});

const weaponWithBonus = (attackBonus: number): ItemDefinition => ({
  ...validWeaponItemFixture,
  weapon: {
    attackBonus
  }
});

const eventOfType = <Type extends TurnEvent["type"]>(
  events: readonly TurnEvent[],
  type: Type
): Extract<TurnEvent, { readonly type: Type }> => {
  const event = events.find(
    (candidate): candidate is Extract<TurnEvent, { readonly type: Type }> =>
      candidate.type === type
  );

  if (event === undefined) {
    throw new Error(`missing event ${type}`);
  }

  return event;
};

