type AsciiOptions = {
  readonly roster?: readonly EnemyDefinition[];
  readonly enemies?: Readonly<Record<string, EnemyEntityInstance>>;
  readonly items?: Readonly<Record<string, GroundItemEntityInstance>>;
  readonly traps?: Readonly<Record<string, TrapEntityInstance>>;
};

const stateFromAscii = (
  seed: string,
  rows: readonly string[],
  options: AsciiOptions = {}
): GameState => {
  const height = rows.length;
  const width = rows[0]?.length ?? 0;
  const tiles = rows.flatMap((row) =>
    [...row].map((char) =>
      createTile(char === "#" ? Terrain.Wall : Terrain.Floor)
    )
  );
  const grid: TileGrid = {
    kind: "tile-grid",
    width,
    height,
    tiles
  };
  const opaque =
    options.roster === undefined
      ? grid
      : {
          ...grid,
          enemyRoster: options.roster
        };
  const base = createInitialState(seed);
  const playerPosition = marker(rows, "@");
  const entities = {
    ...entitiesFromMarkers(options.enemies),
    ...entitiesFromMarkers(options.items),
    ...entitiesFromMarkers(options.traps)
  };

  return {
    ...base,
    floor: {
      ...base.floor,
      geometry: {
        ...base.floor.geometry,
        opaque: opaque as unknown as SerializableRecord
      }
    },
    player: {
      ...base.player,
      position: playerPosition
    },
    entities,
    ids: {
      ...base.ids,
      entityCounters: {
        enemy: maxCounter(entities, "enemy"),
        item: maxCounter(entities, "item"),
        npc: 0,
        trap: maxCounter(entities, "trap")
      }
    }
  };
};

const entitiesFromMarkers = <T extends EntityInstance>(
  entries: Readonly<Record<string, T>> | undefined
): Record<string, T> => {
  if (entries === undefined) {
    return {};
  }

  return Object.fromEntries(
    Object.values(entries).map((entity) => [entity.id, entity])
  );
};

const marker = (rows: readonly string[], char: string): Position => {
  for (let y = 0; y < rows.length; y += 1) {
    const x = rows[y]?.indexOf(char) ?? -1;
    if (x >= 0) {

      return band;
    }
  }

  throw new RangeError(`depth ${depth} is outside configured depth bands`);
};

export const createInitialState = (
  seed: string,
  gameConfig: GameConfig = defaultConfig,
): GameState => {
  const turn = createClock().now();
  const depth = initialDepth(gameConfig);
  const band = depthBandForDepth(depth, gameConfig);
  const runId = runIdForSeed(seed);
  const startPosition = unplacedPosition();
  const playerHp = gameConfig.playerCharacter.stats.hp.start;
  const playerFullness = gameConfig.playerCharacter.stats.fullness.start;

  return {
    version: {
      protocolVersion: PROTOCOL_VERSION,
      engineVersion: ENGINE_VERSION,
    },
    run: {
      runId,
      seed,
      depth,
      band,
      turn,
      terminalStatus: ACTIVE_TERMINAL_STATUS,
    },
    floor: {
      floorId: `floor#${depth}`,
      depth,
      band,
      geometry: {
        refId: `floor-geometry#${depth}`,
        opaque: null,
      },
    },
    player: {
      hp: {
        current: playerHp,
        max: playerHp,
      },
