  it.each(rejectionRows)(
    "rejects out-of-bounds %s execution without changing serialized state",
    ({ effect, makeState, context: contextOverrides, code }) => {
      const state = makeState?.() ?? createInitialState(`effect-oob-${effect.kind}`);
      const before = serialize(state);
      const result = executeBundle(
        state,
