      expect(serialize(result.state)).toBe(before);
      expect(result.events).toHaveLength(1);
      expect(result.events[0]?.type).toBe("effect_rejected");
      expect(result.events[0]?.data).toMatchObject({
        verb: effect.kind,
        effectIndex: 0,
        code
      });
    }
  );
});

