const withWallCells = (
  state: GameState,
  positions: readonly Position[]
): GameState => {
  const grid = gridFrom(state);
  const wallPositions = new Set(positions.map(positionKey));
  const tiles = grid.tiles.map((tile, index) => {
    const position = {
      x: index % grid.width,
      y: Math.floor(index / grid.width)
    };

    return wallPositions.has(positionKey(position)) ? createTile(Terrain.Wall) : tile;
  });

  return {
    ...state,
    floor: {
      ...state.floor,
      geometry: {
        ...state.floor.geometry,
        opaque: {
          ...grid,
          tiles
        } as unknown as SerializableRecord
      }
    }
  };
};

